#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 研学营地教育.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="研学营地教育"
DIM_COUNT=7

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (7 个):
  9.1 政策与标准合规（最新标准号 + 报批 + 名录）
  9.2 学习目标与课程设计（逆向设计 + Kolb + PBL/5E）
  9.3 安全风控与配比（三案 + 三层险 + 营辅比）
  9.4 基地 / 营地选型（基地≠营地 + 资源匹配 + 安全设施）
  9.5 商业模式与获客（B 端校采名录投标 vs C 端私域短视频转介绍）
  9.6 主题特化（自然 / 红色 / 科技 / 出境 各自命门 + 子赛道合规）
  9.7 质量与口碑（教育性可视化 + 反思闭环 + 评价对接 + 复购）

背后的心智模型:
  • 「研学是课程不是行程」——教育属性优先: 研学/营地的本体是**课程**（有学习目标—实施—评价闭环），不是**行程**（景点+讲解词）；从业者用「教育本质」作为对抗旅游化、获客化、速成化的立场锚与对客叙事。
  • 体验—反思闭环（Kolb 圈）——「经验无反思即旅游」: 学习不是「去过/动手过」就发生，而要走完「具体经验→反思观察→抽象概念化→主动实践」的圈；**「反思/复盘」环节的有无，是研学区别于旅游的命门工序**。
  • 「安全是 1，后面才是 0」——安全一票否决 / 风控前置门: 安全/风控是研学营地的第一性约束，是「1」；体验、课程、规模、利润都是这个 1 后面的「0」——1 没了，后面多少 0 都没用。

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "政策与标准合规（最新标准号 + 报批 + 名录）"
  "学习目标与课程设计（逆向设计 + Kolb + PBL/5E）"
  "安全风控与配比（三案 + 三层险 + 营辅比）"
  "基地 / 营地选型（基地≠营地 + 资源匹配 + 安全设施）"
  "商业模式与获客（B 端校采名录投标 vs C 端私域短视频转介绍）"
  "主题特化（自然 / 红色 / 科技 / 出境 各自命门 + 子赛道合规）"
  "质量与口碑（教育性可视化 + 反思闭环 + 评价对接 + 复购）"
)
declare -a DIM_QUESTIONS=(
  "现行研学标准的**最新版本号与实施日期**（重点确认 LB/T 054-2025 已替代 054-2016，是否再有更新版/配套省级办法）；目标地教育局《研学实践管理办法》的报批—备案—审批流程与时间节点；目标省份的研学服务机构名录遴选周期与是否在册；近 12 个月新发的监管文件（如文旅部治理伪研学类）。"
  "目标学段/主题对应的**可测学习目标**怎么写（布鲁姆动词层级）；该主题适配哪个课程框架（多日项目→PBL Gold Standard 七要素；单次探究→5E；通用→Kolb 圈+UbD）；LB/T 092-2025 官方七步课程设计流程与四类手册规范；如何嵌入「反思+公开成果」环节。"
  "本次活动类型对应的**人员配比数值**（研学指导/随团/营辅按年龄分级/安全员，以 LB/T 054-2025 + 地标 + ACA 为准）；三案（活动/安全/应急预案）是否需一车一案+演练；三层险栈投保主体与保额（出境加全球救援险）；高风险环节（涉水/高海拔/交通）的专项处置。"
  "候选场所是**「基地」还是「营地」**（对标 T/CATS 002 / LB/T 054 / ACA 哪套）；其等级认定**真伪**（是否国家级 2017/2018 两批之一，还是省/市/自封）；资源能否支撑课程学习目标（主题对口）；安全设施核查（CCTV/疏散/医疗/周边隐患）、满员容量与雨备替代场地。"
  "这是 **B 端（学校/教育局采购）还是 C 端（家庭付费）**生意，对应完全不同打法——B 端走名录资格+竞争性磋商+教育性方案竞争（非最低价）；C 端走视频号/抖音/小红书种草→小程序/企微私域→美团/携程分销+转介绍引擎；以及对应的工具分层与单位经济（重资产 vs 轻资产张力）。"
  "子赛道**专属命门与合规**——自然教育（在地物种/物候 + LNT 七原则 + LY/T 3329-2022 林草系归口）；红色研学（党史脉络思政课程化 + 仪式感 + 对接大思政课，B 端为主）；科技研学（5E 的 Explain/Elaborate 建构迁移 + 可展示作品 + STEAM 器材）；出境游学（LB/T 091-2025 + 教育部赴境外研学指南 + 汇率/地缘）。"
  "产品的**教育性证据是否可被第三方看见**（对照表/手册质量/公开成果）；Kolb 圈是否闭合（反思不缩水）；学习评价是否对接学分/综合素质评价；C 端口碑是否成复购/转介绍资产；对照行业反模式自查（只游不学/打卡/玩具展示/手册=纪念册）。"
)
declare -a DIM_SOURCES=(
  "文旅部 zwgk.mct.gov.cn（行业标准公告/通知）、教育部 moe.gov.cn、目标省市教育局/文旅局 .gov.cn 官网（报批办法/名录公告）、全国团体标准信息平台 ttbz.org.cn（T/CATS）、国家数字标准馆 ndls.org.cn。**不查百度百科/微信/知乎**。"
  "LB/T 092-2025 条目（文旅部 zwgk.mct.gov.cn）、PBLWorks pblworks.org（Gold Standard 七要素）、BSCS 5E（.edu 托管 PDF）、段玉山《研学旅行课程标准》系列（核心期刊）、本 skill canon 模块。**不依赖 AI 生成器输出当结论**。"
  "LB/T 054-2025 安全管理章（文旅部）、目标地地标（如北京未成年人研学服务规范）、ACA acacamps.org（营辅比年龄分级）、君合等律所合规长稿（三层险责任划分）、本 skill 工具栈安全三件套。"
  "T/CATS 002 条目（国家数字标准馆/团标平台）、教育部 2017/2018 两批国家级名单（moe.gov.cn 原文核验等级）、目标省市研学基地名录、实地踩点报告（不可凭 vendor/招商图册）、ACA 标准。"
  "目标地政府采购/招标公告平台（B 端真实标的+竞争性磋商规则）、多鲸《素质教育趋势报告》营地研学专章（市场结构/客单价/集中度，注意口径 caveat）、世纪明德新三板财报（龙头盈利模型反例）、抖音/美团本地生活规则页（C 端获客）。"
  "自然—国家林草局 forestry.gov.cn（LY/T 3329 解读）+ lnt.org；红色—教基一8号育人导向+地方爱国主义教育基地名单；科技—PBLWorks/BSCS 5E+器材 vendor 官页；出境—教育部 jsj.moe.gov.cn 赴境外研学指南+LB/T 091。"
  "本 skill §6 质量基准+反模式、段玉山课程评价/表现性评价（核心期刊）、UbD 评价证据观、运营者公开案例（如游美转介绍模型，作参照非 benchmark）、目标地综合素质评价对接政策。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "「现行标准：LB/T 054-{版本}（实施 {日期}）+ 出境 091 + 课程线路 092；目标地报批流程 = {步骤+时间节点}；名录资格 = {在册/需申请，周期 {N} 年}；近期监管变化 = {有/无 + 文件名日期}。」"
  "「推荐框架 = {Kolb/PBL/5E/UbD 哪个+理由}；可测目标示例 = 「能{布鲁姆动词}…」×N；反思/成果环节 = {具体设计}；是否闭合 Kolb 圈 = {是/否+缺口}。」"
  "「配比要求 = 研学指导 ≥{X}、随团 ≥{Y}、营辅 {年龄段:比例}、安全员 {N}/团；三案 = {齐/缺哪项}；三层险 = {校方/旅行社/意外 投保主体齐否+出境救援}；高风险专项 = {有/无}。」"
  "「场所类型 = 基地/营地（对标 {标准}）；等级 = {国家级哪批/省市级/自封，已核验}；资源匹配 = {支撑/不支撑学习目标};安全设施 = {核查清单结果}；容量/雨备 = {满员动线+室内替代}。」"
  "「生意类型 = B/C 端；B 端 = {名录资格+采购方式+教育性卖点}；C 端 = {获客渠道+私域闭环+转介绍机制}；资产模型 = 重/轻 + 单位经济关键变量；数据口径 caveat = {引用了哪份报告哪年}。」"
  "「子赛道 = {自然/红色/科技/出境}；命门 = {该子赛道专属方法}；专属合规 = {LNT/思政/作品化/出境险与指南}；在地差异化资源 = {本地独特资源点}。」"
  "「教育性证据 = {对照表/手册/成果 有无}；Kolb 闭合 = {是/否};评价对接 = {学分/综合素质评价 是否};口碑资产 = {复购/转介绍机制有无}；反模式自查 = {命中哪几条需修正}。」"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
